async def _gif_stream():
    yield HIDE_CURSOR
    i = 0
    try:
        while True:
            yield CLEAR + _GIF_GREEN + _GIF_FRAMES[i % len(_GIF_FRAMES)] + RESET
            await asyncio.sleep(0.029)
            i += 1
    finally:
        yield SHOW_CURSOR + CLEAR


@router.get('/lambda')
async def gif(request: Request):
    ua = request.headers.get('user-agent', '')
    if not ua.lower().startswith('curl'):
        return HTMLResponse(_gif_html())
    return StreamingResponse(_gif_stream(), media_type='text/plain')

